 p_id=>wwv_flow_imp.id(117184113460742250041)
,p_plug_name=>'Movies'
,p_region_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_imp.id(111750344133569152989)
,p_plug_display_sequence=>20
,p_plug_new_grid_row=>false
,p_plug_new_grid_column=>false
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT m.nameM, m.release_date',
'    FROM users u',
'    INNER JOIN person p ON u.idPerson = p.idPerson',
'    INNER JOIN movie m ON',
'        (',
'            (TRUNC((SYSDATE - p.date_of_birth) / 365.25) < 7 AND m.age_rating = ''G - General Audiences'') OR',
'            (TRUNC((SYSDATE - p.date_of_birth) / 365.25) >= 7 AND TRUNC((SYSDATE - p.date_of_birth) / 365.25)< 13 AND m.age_rating IN (''PG - Parental Guidance Suggested'', ''G - General Audiences'')) OR',
'            (TRUNC((SYSDATE - p.date_of_birth) / 365.25) >= 13 AND TRUNC((SYSDATE - p.date_of_birth) / 365.25) < 17 AND m.age_rating IN (''PG-13 - Parents Strongly Cautioned'', ''PG - Parental Guidance Suggested'', ''G - General Audiences'')) OR',
'            (TRUNC((SYSDATE - p.date_of_birth) / 365.25) = 17 AND m.age_rating IN (''R - Restricted'', ''PG-13 - Parents Strongly Cautioned'', ''PG - Parental Guidance Suggested'', ''G - General Audiences'')) OR',
'            (TRUNC((SYSDATE - p.date_of_birth) / 365.25) > 17 AND m.age_rating IN (''NC-17 - Adults Only'', ''R - Restricted'', ''PG-13 - Parents Strongly Cautioned'', ''PG - Parental Guidance Suggested'', ''G - General Audiences''))',
'        )',
'    WHERE u.idPerson = :P18_USERS;'))
